export default function videoExerciseModalContent(exercise) {
    return (
    /* html */
    "<span class=\"block\">\n      <input value=\"video\" hidden id=\"exerciseInputsType\">\n\n      <div class=\"flex flex-col\">\n        <div class=\"text-center w-full\">\n          <input class=\"rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-base font-medium text-gray-700 focus:outline-none w-full h-12\" id=\"modal-title\" placeholder=\"Exercise name\" autocomplete=\"off\" required maxlength=\"100\" value=\"".concat(exercise.name, "\">\n        </div>\n        \n        <div class=\"text-center w-full mt-3\">\n          <input class=\"rounded-md border border-gray-300 shadow-sm px-4 py-2 bg-white text-base font-medium text-gray-700 focus:outline-none w-full h-12\" id=\"video-url\" placeholder=\"Youtube Video URL\" required maxlength=\"100\" value=\"").concat(exercise.url, "\">\n        </div>\n\n        <div class=\"mt-3 w-full h-[200px] xs:h-[300px] sm:h-[300px] md:h-[300px]\" id=\"player\"></div>\n\n        <div class=\"flex mt-3\">\n          <div class=\"w-1/3 text-center py-4\">\n            <input type=\"checkbox\" id=\"customTimeCheckBox\" ").concat(exercise.period ? 'checked' : '', ">\n            <div><label for=\"customTimeCheckBox\" class=\"cursor-pointer\">Time interval</label></div>\n          </div>\n\n          <div class=\"ml-4 video-seconds-input opacity-50\">\n            <label for=\"videoStartSeconds\">Start (seconds)</label>\n            <input class=\"p-2 border border-gray-400 rounded outline-none w-full\" type=\"number\" readonly value=\"").concat(exercise.period ? exercise.period.startSeconds : '0', "\" id=\"videoStartSeconds\">\n          </div>\n\n          <div class=\"ml-4 video-seconds-input opacity-50\">\n            <label for=\"videoEndSeconds\">End (seconds)</label>\n            <input class=\"p-2 border border-gray-400 rounded outline-none w-full\" type=\"number\" readonly value=\"").concat(exercise.period ? exercise.period.endSeconds : '10', "\" id=\"videoEndSeconds\">\n          </div>\n        </div>\n      </div>\n    </span>"));
}
